const duchod = Number(
    context.workflow['1d1135da-70a4-4cbb-84be-e0e995da6e36']?.result?.[0]?.['duchod']
);

if (!birthDate || !jobIncome || !duchod) {
    return {
        error: "Missing data",
        birthDate,
        jobIncome,
        duchod_raw: duchod
    };
}

// ===== 2) Věk =====
const today = new Date();
const born = new Date(birthDate);

let age = today.getFullYear() - born.getFullYear();
const monthDiff = today.getMonth() - born.getMonth();
if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < born.getDate())) {
    age--;
}

// ===== 3) Kolik let zbývá do 65 =====
const yearsTo65 = 65 - age;
const monthsTo65 = yearsTo65 * 12;

// ===== 4) Měsíční rozdíl příjem − duchod =====
const monthlyDiff = jobIncome - duchod;

// ===== 5) Celková ztráta =====
const totalLoss = monthlyDiff * monthsTo65;

// ===== 6) Výsledek =====
return {
    age,
    yearsTo65,
    monthsTo65,
    duchod,
    monthlyDiff,
    totalLoss
};

