// 1. NAČTENÍ PROMĚNNÝCH
// income_job
const incomeRaw = variables['51b18477-0d15-47bb-8223-4d0a25c61e6a'];
// family_kids_number
const kidsRaw = variables['a9f601d7-3ecc-4d6b-b0b8-0795d4e5d47e'];

const income = Number(incomeRaw) || 0;
const kids = Number(kidsRaw) || 0;

if (income === 0) {
    return { propad_14_dni: 0, ocr_vysledek: 0 };
}

// --- ČÁST A: VÝPOČET OČR (DÁVKA) ---
const hranice1 = 1571;
const hranice2 = 2356;
const hranice3 = 4712;

// DVZ
const dvz = (income * 12) / 365;

// Redukce DVZ
let rdz = 0;
if (dvz <= hranice1) {
    rdz = dvz * 0.9;
} else if (dvz <= hranice2) {
    rdz = (hranice1 * 0.9) + ((dvz - hranice1) * 0.6);
} else if (dvz <= hranice3) {
    rdz = (hranice1 * 0.9) + ((hranice2 - hranice1) * 0.6) + ((dvz - hranice2) * 0.3);
} else {
    rdz = (hranice1 * 0.9) + ((hranice2 - hranice1) * 0.6) + ((hranice3 - hranice2) * 0.3);
}
rdz = Math.ceil(rdz);

// OČR na 1 den
let ocrDenni = Math.ceil(rdz * 0.6);

// Pokud nemá děti, nemá nárok na OČR (technicky), dáváme 0
if (kids < 1) ocrDenni = 0;

// Celkové OČR, které člověk dostane (placeno max 9 dní)
// Pozn: Pokud by šlo o samoživitele, bylo by to 16, zde počítáme standard 9.
const ocrCelkemVyplaceno = ocrDenni * 9;


// --- ČÁST B: VÝPOČET ČISTÉ MZDY (ODHAD PRO ROK 2025) ---
// Abychom zjistili propad, musíme vědět, kolik by bral čistého, kdyby chodil do práce.

// Odvody zaměstnance (Soc + Zdr) cca 11.6 % (7,1% soc + 4,5% zdr)
const odvody = income * 0.116;

// Daň 15 % z hrubé
let dan = income * 0.15;

// Sleva na poplatníka (2570 Kč měsíčně)
const slevaPoplatnik = 2570;
// Zjednodušená sleva na děti (průměr cca 1267 Kč na dítě - přesně je to 1. dítě 1267, 2. 1617...)
// Pro účel kalkulačky propadu stačí základní odhad.
const slevaDeti = kids * 1267;

// Výpočet skutečné daně (nemůže jít pod nulu, pokud nepočítáme daňový bonus, 
// ale pro propad příjmu stačí předpokládat, že daň snížíme max na 0)
let skutecnaDan = dan - slevaPoplatnik - slevaDeti;
if (skutecnaDan < 0) skutecnaDan = 0; // Ignorujeme daňový bonus pro zjednodušení

const cistaMzdaMesicni = income - odvody - skutecnaDan;

// Čistá mzda na 1 den (průměrně 30.42 dní v měsíci)
const cistaMzdaDenni = cistaMzdaMesicni / 30.42;


// --- ČÁST C: VÝPOČET PROPADU ZA 14 DNÍ ---

// 1. Kolik by vydělal normálně za 14 dní (čistého)
const ocekavanyPrijem14dni = cistaMzdaDenni * 14;

// 2. Kolik reálně dostane (9 dní OČR + 5 dní nic)
const realnyPrijem14dni = ocrCelkemVyplaceno; // (za dny 10-14 je 0)

// 3. Propad (Rozdíl)
const propad = ocekavanyPrijem14dni - realnyPrijem14dni;


// --- VÝSTUP ---
return {
    ocr_denni: ocrDenni,
    ocr_vyplaceno_celkem: ocrCelkemVyplaceno, // To co mu přijde na účet od státu
    odhad_ciste_mzdy_den: Math.round(cistaMzdaDenni),
    ocekavany_prijem_14_dni: Math.round(ocekavanyPrijem14dni), // Kolik by měl normálně
    propad_prijmu: Math.round(propad) // VÝSLEDEK: O kolik přijde
};

