if (dvz <= hranice1) {
    rdz = dvz * 0.9;
} else if (dvz <= hranice2) {
    rdz = (hranice1 * 0.9) + ((dvz - hranice1) * 0.6);
} else if (dvz <= hranice3) {
    rdz = (hranice1 * 0.9) + ((hranice2 - hranice1) * 0.6) + ((dvz - hranice2) * 0.3);
} else {
    rdz = (hranice1 * 0.9) + ((hranice2 - hranice1) * 0.6) + ((hranice3 - hranice2) * 0.3);
}
rdz = Math.ceil(rdz);

// OČR na 1 den
let ocrDenni = Math.ceil(rdz * 0.6);

// Pokud nemá děti, nemá nárok na OČR (technicky), dáváme 0
if (kids < 1) ocrDenni = 0;

